import React, { useState } from 'react';
import { Lock, User } from 'lucide-react';

interface Props {
  onSubmit: (email: string, password: string) => Promise<void>;
}

const LoginPage: React.FC<Props> = ({ onSubmit }) => {
  const [email, setEmail] = useState<string>('');
  const [password, setPassword] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string>('');

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setError('');

    if (!email || !password) {
      setError('Both fields are required.');
      return;
    }

    if (!/\S+@\S+\.\S+/.test(email)) {
      setError('Please enter a valid email address.');
      return;
    }

    setLoading(true);
    try {
      await onSubmit(email, password);
    } catch (err) {
      setError('Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gray-100">
      <form 
        onSubmit={handleSubmit} 
        aria-label="Login Form" 
        className="bg-white backdrop-blur-lg rounded-xl shadow-lg p-8 max-w-md w-full"
      >
        <fieldset className="mb-4">
          <legend className="text-2xl font-bold text-gray-800">Login</legend>

          <div className="mb-4">
            <label htmlFor="email-input" className="block text-gray-700 mb-1">
              <User className="inline mr-2" />
              Email
            </label>
            <input 
              id="email-input" 
              type="email" 
              placeholder="Enter your email" 
              required 
              value={email} 
              onChange={(e) => setEmail(e.target.value)} 
              className="w-full p-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              aria-describedby={error ? "email-error" : undefined}
            />
            {error && <span id="email-error" className="text-red-600 text-sm">{error}</span>}
          </div>

          <div className="mb-4">
            <label htmlFor="password-input" className="block text-gray-700 mb-1">
              <Lock className="inline mr-2" />
              Password
            </label>
            <input 
              id="password-input" 
              type="password" 
              placeholder="Enter your password" 
              required 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              className="w-full p-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
              aria-describedby={error ? "password-error" : undefined}
            />
            {error && <span id="password-error" className="text-red-600 text-sm">{error}</span>}
          </div>

          <button 
            type="submit" 
            disabled={loading} 
            className={`w-full p-2 rounded-lg text-white ${loading ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700 transition-all duration-300 active:scale-95'}`}
            aria-live="polite"
          >
            {loading ? 'Loading...' : 'Login'}
          </button>
        </fieldset>
      </form>
    </div>
  );
};

export default LoginPage;

